def check_pandaspipe_method_should_be_preferred_over_long_chains_of_instructions(node):
    if isinstance(node, dict) and node.get('node_type') == 'Attribute':
        attr = node.get('attr')
        pandas_methods = ['fillna', 'dropna', 'groupby', 'sort_values', 'reset_index', 'sum', 'mean', 'median']
        if attr in pandas_methods and len([n for n in node['children'] if n['node_type'] == 'Call' and n['func'] in pandas_methods]) >= 3:
            return True
    return False
